## h1 <- h1 coupling contributions
from . import logger, tools, ascontiguousarray

# CCAA <- CCAA
def compute_sigma_vector__H1__h1_h1__CCAA_CCAA(mr_adc, X, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    ccaa = mr_adc.h1.ccaa

    ## Two-electron integrals
    v_xaax = mr_adc.v2e.xaax
    v_xxaa = mr_adc.v2e.xxaa
    v_xxxx = mr_adc.v2e.xxxx

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa
    rdm_cccaaa = mr_adc.rdm.cccaaa

    sigma_KLWU  = 2 * einsum('KiWx,LUxi->KLWU', X, v_xaax, optimize = einsum_type)
    sigma_KLWU -= einsum('KiWx,LixU->KLWU', X, v_xxaa, optimize = einsum_type)
    sigma_KLWU -= einsum('KixU,LixW->KLWU', X, v_xxaa, optimize = einsum_type)
    sigma_KLWU -= einsum('KixW,LUxi->KLWU', X, v_xaax, optimize = einsum_type)
    sigma_KLWU += 2 * einsum('LiUx,KWxi->KLWU', X, v_xaax, optimize = einsum_type)
    sigma_KLWU -= einsum('LiUx,KixW->KLWU', X, v_xxaa, optimize = einsum_type)
    sigma_KLWU -= einsum('LixU,KWxi->KLWU', X, v_xaax, optimize = einsum_type)
    sigma_KLWU -= einsum('LixW,KixU->KLWU', X, v_xxaa, optimize = einsum_type)
    sigma_KLWU += einsum('ijUW,KjLi->KLWU', X, v_xxxx, optimize = einsum_type)
    sigma_KLWU -= einsum('KiWx,LUyi,xy->KLWU', X, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KiWx,Lixy,Uy->KLWU', X, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KiWx,LiyU,xy->KLWU', X, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KiWx,Liyz,Uyxz->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= einsum('KiWx,Lyxi,Uy->KLWU', X, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KiWx,Lyzi,Uzyx->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KixU,Lixy,Wy->KLWU', X, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KixU,LiyW,xy->KLWU', X, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KixU,Liyz,Wyxz->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('KixU,Lyzi,Wzxy->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('KixU,Lyzi,Wzyx->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KixW,LUyi,xy->KLWU', X, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('KixW,Lyxi,Uy->KLWU', X, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('KixW,Lyzi,Uzxy->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('KixW,Lyzi,Uzyx->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Kixy,LUxi,Wy->KLWU', X, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= einsum('Kixy,LUyi,Wx->KLWU', X, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Kixy,LUzi,Wzxy->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Kixy,LixW,Uy->KLWU', X, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Kixy,Lixz,UWyz->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kixy,Lixz,UWzy->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Kixy,LiyU,Wx->KLWU', X, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kixy,Liyz,UWxz->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Kixy,Liyz,UWzx->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Kixy,LizU,Wzxy->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kixy,LizU,Wzyx->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kixy,LizW,Uzxy->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Kixy,LizW,Uzyx->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('Kixy,Lizw,UWzwxy->KLWU', X, v_xxaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('Kixy,Lizw,UWzwyx->KLWU', X, v_xxaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('Kixy,Lizw,UWzxwy->KLWU', X, v_xxaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('Kixy,Lizw,UWzywx->KLWU', X, v_xxaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kixy,Lizw,UWzyxw->KLWU', X, v_xxaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kixy,Lzwi,UWwxzy->KLWU', X, v_xaax, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Kixy,Lzwi,UWwzxy->KLWU', X, v_xaax, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kixy,Lzxi,UWyz->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Kixy,Lzxi,UWzy->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/3 * einsum('Kixy,Lzyi,UWxz->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 2/3 * einsum('Kixy,Lzyi,UWzx->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= einsum('LiUx,KWyi,xy->KLWU', X, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('LiUx,Kixy,Wy->KLWU', X, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('LiUx,KiyW,xy->KLWU', X, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('LiUx,Kiyz,Wyxz->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= einsum('LiUx,Kyxi,Wy->KLWU', X, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('LiUx,Kyzi,Wzyx->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('LixU,KWyi,xy->KLWU', X, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('LixU,Kyxi,Wy->KLWU', X, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('LixU,Kyzi,Wzxy->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('LixU,Kyzi,Wzyx->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('LixW,Kixy,Uy->KLWU', X, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('LixW,KiyU,xy->KLWU', X, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('LixW,Kiyz,Uyxz->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('LixW,Kyzi,Uzxy->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('LixW,Kyzi,Uzyx->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Lixy,KWxi,Uy->KLWU', X, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= einsum('Lixy,KWyi,Ux->KLWU', X, v_xaax, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Lixy,KWzi,Uzxy->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Lixy,KixU,Wy->KLWU', X, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Lixy,Kixz,UWyz->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Lixy,Kixz,UWzy->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/2 * einsum('Lixy,KiyW,Ux->KLWU', X, v_xxaa, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Lixy,Kiyz,UWxz->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Lixy,Kiyz,UWzx->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Lixy,KizU,Wzxy->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Lixy,KizU,Wzyx->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Lixy,KizW,Uzxy->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Lixy,KizW,Uzyx->KLWU', X, v_xxaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Lixy,Kizw,UWzxyw->KLWU', X, v_xxaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Lixy,Kizw,UWzyxw->KLWU', X, v_xxaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('Lixy,Kzwi,UWwxyz->KLWU', X, v_xaax, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Lixy,Kzwi,UWwxzy->KLWU', X, v_xaax, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('Lixy,Kzwi,UWwyxz->KLWU', X, v_xaax, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('Lixy,Kzwi,UWwyzx->KLWU', X, v_xaax, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('Lixy,Kzwi,UWwzyx->KLWU', X, v_xaax, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Lixy,Kzxi,UWyz->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Lixy,Kzxi,UWzy->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 2/3 * einsum('Lixy,Kzyi,UWxz->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/3 * einsum('Lixy,Kzyi,UWzx->KLWU', X, v_xaax, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('ijUx,KjLi,Wx->KLWU', X, v_xxxx, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('ijWx,KiLj,Ux->KLWU', X, v_xxxx, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('ijxy,KiLj,UWxy->KLWU', X, v_xxxx, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/3 * einsum('ijxy,KiLj,UWyx->KLWU', X, v_xxxx, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('KiWx,Liyz,yz,Ux->KLWU', X, v_xxaa, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/4 * einsum('KiWx,Lyzi,zy,Ux->KLWU', X, v_xaax, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('KixU,Liyz,yz,Wx->KLWU', X, v_xxaa, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/4 * einsum('KixU,Lyzi,zy,Wx->KLWU', X, v_xaax, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('Kixy,Lizw,zw,UWxy->KLWU', X, v_xxaa, rdm_ca, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/3 * einsum('Kixy,Lizw,zw,UWyx->KLWU', X, v_xxaa, rdm_ca, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/12 * einsum('Kixy,Lzwi,wz,UWxy->KLWU', X, v_xaax, rdm_ca, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kixy,Lzwi,wz,UWyx->KLWU', X, v_xaax, rdm_ca, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('LiUx,Kiyz,yz,Wx->KLWU', X, v_xxaa, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/4 * einsum('LiUx,Kyzi,zy,Wx->KLWU', X, v_xaax, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLWU -= 1/2 * einsum('LixW,Kiyz,yz,Ux->KLWU', X, v_xxaa, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/4 * einsum('LixW,Kyzi,zy,Ux->KLWU', X, v_xaax, rdm_ca, rdm_ca, optimize = einsum_type)
    sigma_KLWU += 1/3 * einsum('Lixy,Kizw,zw,UWxy->KLWU', X, v_xxaa, rdm_ca, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU += 1/6 * einsum('Lixy,Kizw,zw,UWyx->KLWU', X, v_xxaa, rdm_ca, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Lixy,Kzwi,wz,UWxy->KLWU', X, v_xaax, rdm_ca, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/12 * einsum('Lixy,Kzwi,wz,UWyx->KLWU', X, v_xaax, rdm_ca, rdm_ccaa, optimize = einsum_type)
    sigma[ccaa] += ascontiguousarray(sigma_KLWU).reshape(-1)

    mr_adc.log.timer_debug("computing sigma H1 h1-h1 CCAA-CCAA", *cput1)

# CCEA <- CCAA
def compute_sigma_vector__H1__h1_h1__CCEA_CCAA(mr_adc, X, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    ccea = mr_adc.h1.ccea

    ## Molecular Orbitals Energies
    e_extern = mr_adc.mo_energy.e
    
    ## One-electron integrals
    h_aa = mr_adc.h1eff.aa
    h_ae = mr_adc.h1eff.ae

    ## Two-electron integrals
    v_aaae = mr_adc.v2e.aaae
    v_xxae = mr_adc.v2e.xxae
    v_xaex = mr_adc.v2e.xaex
    v_aaaa = mr_adc.v2e.aaaa

    ## Amplitudes
    t1_ae = mr_adc.t1.ae 
    t1_aaae = mr_adc.t1.aaae

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa
    rdm_cccaaa = mr_adc.rdm.cccaaa

    sigma_KLCW  = einsum('KLxW,xC->KLCW', X, h_ae, optimize = einsum_type)
    sigma_KLCW += einsum('KLxy,yWxC->KLCW', X, v_aaae, optimize = einsum_type)
    sigma_KLCW -= einsum('KixW,LixC->KLCW', X, v_xxae, optimize = einsum_type)
    sigma_KLCW -= einsum('LiWx,KixC->KLCW', X, v_xxae, optimize = einsum_type)
    sigma_KLCW += 2 * einsum('LiWx,ixCK->KLCW', X, v_xaex, optimize = einsum_type)
    sigma_KLCW -= einsum('LixW,ixCK->KLCW', X, v_xaex, optimize = einsum_type)
    sigma_KLCW += einsum('KLxW,C,xC->KLCW', X, e_extern, t1_ae, optimize = einsum_type)
    sigma_KLCW += einsum('KLxy,C,yxWC->KLCW', X, e_extern, t1_aaae, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('KLxy,xC,Wy->KLCW', X, h_ae, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= einsum('KLxW,xy,yC->KLCW', X, h_aa, t1_ae, optimize = einsum_type)
    sigma_KLCW += einsum('KLxy,Wz,yxzC->KLCW', X, h_aa, t1_aaae, optimize = einsum_type)
    sigma_KLCW -= einsum('KLxy,xz,yzWC->KLCW', X, h_aa, t1_aaae, optimize = einsum_type)
    sigma_KLCW -= einsum('KLxy,yz,zxWC->KLCW', X, h_aa, t1_aaae, optimize = einsum_type)
    sigma_KLCW -= einsum('KLxy,zC,Wyzx->KLCW', X, t1_ae, v_aaaa, optimize = einsum_type)
    sigma_KLCW -= einsum('KLxy,zwWC,xwyz->KLCW', X, t1_aaae, v_aaaa, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('KLxW,xyzC,yz->KLCW', X, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCW += einsum('KLxW,yzxC,zy->KLCW', X, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/3 * einsum('KLxy,xzwC,Wwyz->KLCW', X, v_aaae, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW += 1/6 * einsum('KLxy,xzwC,Wwzy->KLCW', X, v_aaae, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('KLxy,yWzC,xz->KLCW', X, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/6 * einsum('KLxy,yzwC,Wwxz->KLCW', X, v_aaae, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW += 1/3 * einsum('KLxy,yzwC,Wwzx->KLCW', X, v_aaae, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('KLxy,yzxC,Wz->KLCW', X, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('KLxy,zWxC,yz->KLCW', X, v_aaae, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= 1/2 * einsum('KLxy,zwxC,Wzyw->KLCW', X, v_aaae, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('KixW,LiyC,xy->KLCW', X, v_xxae, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('Kixy,LixC,Wy->KLCW', X, v_xxae, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= 1/6 * einsum('Kixy,LizC,Wzxy->KLCW', X, v_xxae, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW -= 1/3 * einsum('Kixy,LizC,Wzyx->KLCW', X, v_xxae, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('LiWx,KiyC,xy->KLCW', X, v_xxae, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= einsum('LiWx,iyCK,xy->KLCW', X, v_xaex, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('LixW,iyCK,xy->KLCW', X, v_xaex, rdm_ca, optimize = einsum_type)
    sigma_KLCW += 1/2 * einsum('Lixy,KiyC,Wx->KLCW', X, v_xxae, rdm_ca, optimize = einsum_type)
    sigma_KLCW -= 1/3 * einsum('Lixy,KizC,Wzxy->KLCW', X, v_xxae, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW -= 1/6 * einsum('Lixy,KizC,Wzyx->KLCW', X, v_xxae, rdm_ccaa, optimize = einsum_type)
