# CCEE <- CCAA
def compute_sigma_vector__H1__h1_h1__CCEE_CCAA(mr_adc, X, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    ccee = mr_adc.h1.ccee

    ## Molecular Orbitals Energies
    e_extern = mr_adc.mo_energy.e

    ## One-electron integrals
    h_aa = mr_adc.h1eff.aa

    ## Two-electron integrals
    v_aeae = mr_adc.v2e.aeae
    v_aaaa = mr_adc.v2e.aaaa

    ## Amplitudes
    t1_aaee = mr_adc.t1.aaee

    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa

    sigma_KLCD  = einsum('KLxy,xCyD->KLCD', X, v_aeae, optimize = einsum_type)
    sigma_KLCD += einsum('KLxy,C,xyCD->KLCD', X, e_extern, t1_aaee, optimize = einsum_type)
    sigma_KLCD += einsum('KLxy,D,xyCD->KLCD', X, e_extern, t1_aaee, optimize = einsum_type)
    sigma_KLCD -= einsum('KLxy,xz,zyCD->KLCD', X, h_aa, t1_aaee, optimize = einsum_type)
    sigma_KLCD -= einsum('KLxy,yz,xzCD->KLCD', X, h_aa, t1_aaee, optimize = einsum_type)
    sigma_KLCD -= einsum('KLxy,zwCD,xzyw->KLCD', X, t1_aaee, v_aaaa, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLxy,xCzD,yz->KLCD', X, v_aeae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLxy,zCyD,xz->KLCD', X, v_aeae, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLxy,C,xzCD,yz->KLCD', X, e_extern, t1_aaee, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLxy,C,zyCD,xz->KLCD', X, e_extern, t1_aaee, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLxy,D,xzCD,yz->KLCD', X, e_extern, t1_aaee, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/2 * einsum('KLxy,D,zyCD,xz->KLCD', X, e_extern, t1_aaee, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,xz,zwCD,yw->KLCD', X, h_aa, t1_aaee, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,yz,wzCD,xw->KLCD', X, h_aa, t1_aaee, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,zw,xzCD,yw->KLCD', X, h_aa, t1_aaee, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,zw,zyCD,xw->KLCD', X, h_aa, t1_aaee, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,xzCD,ywuz,uw->KLCD', X, t1_aaee, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KLxy,xzCD,yzwu,wu->KLCD', X, t1_aaee, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,xzCD,zwuv,yuwv->KLCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/3 * einsum('KLxy,zwCD,xuvw,yuvz->KLCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/6 * einsum('KLxy,zwCD,xuvw,yuzv->KLCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/6 * einsum('KLxy,zwCD,xuvz,yuvw->KLCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/3 * einsum('KLxy,zwCD,xuvz,yuwv->KLCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,zwCD,xuyw,zu->KLCD', X, t1_aaee, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,zwCD,xzuv,yvwu->KLCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,zwCD,xzuw,yu->KLCD', X, t1_aaee, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,zwCD,xzyu,wu->KLCD', X, t1_aaee, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= 1/6 * einsum('KLxy,zwCD,yuvw,xuvz->KLCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/3 * einsum('KLxy,zwCD,yuvw,xuzv->KLCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/3 * einsum('KLxy,zwCD,yuvz,xuvw->KLCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD -= 1/6 * einsum('KLxy,zwCD,yuvz,xuwv->KLCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,zwCD,ywuv,xvzu->KLCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,zwCD,ywuz,xu->KLCD', X, t1_aaee, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,zyCD,xwuz,uw->KLCD', X, t1_aaee, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD -= einsum('KLxy,zyCD,xzwu,wu->KLCD', X, t1_aaee, v_aaaa, rdm_ca, optimize = einsum_type)
    sigma_KLCD += 1/2 * einsum('KLxy,zyCD,zwuv,xuwv->KLCD', X, t1_aaee, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma[ccee] += ascontiguousarray(sigma_KLCD).reshape(-1)

    mr_adc.log.timer_debug("computing sigma H1 h1-h1 CCEE-CCAA", *cput1)
 
