# CAAA <- CCAA
def compute_sigma_vector__H1__h1_h1__CAAA_CCAA(mr_adc, X, sigma):
    cput1 = (logger.process_clock(), logger.perf_counter())

    # Einsum definition from kernel
    einsum = mr_adc.interface.einsum
    einsum_type = mr_adc.interface.einsum_type

    #Excitation Manifold
    caaa__aaaa = mr_adc.h1.caaa__aaaa
    caaa__abab = mr_adc.h1.caaa__abab

    ## Indices
    aa_tril_ind = mr_adc.h1.aa_tril_ind 

    ## Molecular Orbitals Energies
    e_cvs = mr_adc.mo_energy.x
 
    ## One-electron integrals
    h_aa = mr_adc.h1eff.aa
    h_xa = mr_adc.h1eff.xa
 
    ## Two-electron integrals
    v_xxxa = mr_adc.v2e.xxxa
    v_aaaa = mr_adc.v2e.aaaa
    v_xaaa = mr_adc.v2e.xaaa
  
    ## Amplitudes
    t1_xa = mr_adc.t1.xa
    t1_xaaa = mr_adc.t1.xaaa
  
    # Reduced Density Matrices
    rdm_ca = mr_adc.rdm.ca
    rdm_ccaa = mr_adc.rdm.ccaa
    rdm_cccaaa = mr_adc.rdm.cccaaa
    rdm_ccccaaaa = mr_adc.rdm.ccccaaaa

    sigma_KWUV_aaaa =- einsum('KiUV,iW->KWUV', X, h_xa, optimize = einsum_type)
    sigma_KWUV_aaaa += einsum('KiVU,iW->KWUV', X, h_xa, optimize = einsum_type)
    sigma_KWUV_aaaa += einsum('KiUV,i,iW->KWUV', X, e_cvs, t1_xa, optimize = einsum_type)
    sigma_KWUV_aaaa -= einsum('KiVU,i,iW->KWUV', X, e_cvs, t1_xa, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('KiUx,iW,Vx->KWUV', X, h_xa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KiVx,iW,Ux->KWUV', X, h_xa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KixU,iW,Vx->KWUV', X, h_xa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('KixV,iW,Ux->KWUV', X, h_xa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/6 * einsum('Kixy,iW,UVxy->KWUV', X, h_xa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/6 * einsum('Kixy,iW,UVyx->KWUV', X, h_xa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa -= einsum('KiUV,Wx,ix->KWUV', X, h_aa, t1_xa, optimize = einsum_type)
    sigma_KWUV_aaaa += einsum('KiVU,Wx,ix->KWUV', X, h_aa, t1_xa, optimize = einsum_type)
    sigma_KWUV_aaaa -= einsum('KiUV,iWxy,yx->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('KiUV,ixyW,xy->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('KiUx,iWyx,Vy->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('KiUx,iWyz,Vzxy->KWUV', X, v_xaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa += einsum('KiUx,ixVy,Wy->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= einsum('KiUx,ixyW,Vy->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KiUx,iyVx,Wy->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KiUx,iyVz,Wxzy->KWUV', X, v_xaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('KiUx,iyzW,Vyzx->KWUV', X, v_xaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa += einsum('KiVU,iWxy,yx->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KiVU,ixyW,xy->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KiVx,iWyx,Uy->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KiVx,iWyz,Uzxy->KWUV', X, v_xaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa -= einsum('KiVx,ixUy,Wy->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += einsum('KiVx,ixyW,Uy->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('KiVx,iyUx,Wy->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa += 1/2 * einsum('KiVx,iyUz,Wxzy->KWUV', X, v_xaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KiVx,iyzW,Uyzx->KWUV', X, v_xaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KixU,iWyx,Vy->KWUV', X, v_xaaa, rdm_ca, optimize = einsum_type)
    sigma_KWUV_aaaa -= 1/2 * einsum('KixU,iWyz,Vzxy->KWUV', X, v_xaaa, rdm_ccaa, optimize = einsum_type)
