    sigma_KWCU_aaaa += 1/6 * einsum('KixU,iyCz,Wxyz->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_aaaa -= 1/6 * einsum('KixU,iyCz,Wxzy->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_aaaa -= 1/2 * einsum('Kixy,ixCy,UW->KWCU', X, v_xaea, rdm_ca, optimize = einsum_type)
    sigma_KWCU_aaaa += 1/6 * einsum('Kixy,ixCz,UzWy->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_aaaa -= 1/6 * einsum('Kixy,ixCz,UzyW->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_aaaa += einsum('Kixy,iyCx,UW->KWCU', X, v_xaea, rdm_ca, optimize = einsum_type)
    sigma_KWCU_aaaa -= 1/3 * einsum('Kixy,iyCz,UzWx->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_aaaa += 1/3 * einsum('Kixy,iyCz,UzxW->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_aaaa += 1/6 * einsum('Kixy,izCw,UwzWxy->KWCU', X, v_xaea, rdm_cccaaa, optimize = einsum_type)
    sigma_KWCU_aaaa -= 1/6 * einsum('Kixy,izCw,UwzxWy->KWCU', X, v_xaea, rdm_cccaaa, optimize = einsum_type)
    sigma_KWCU_aaaa -= 1/2 * einsum('Kixy,izCx,UzWy->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_aaaa += 1/6 * einsum('Kixy,izCy,UzWx->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_aaaa -= 1/6 * einsum('Kixy,izCy,UzxW->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma[caea__aaaa] += ascontiguousarray(sigma_KWCU_aaaa).reshape(-1)

    sigma_KWCU_abab =- 1/2 * einsum('KixU,iyCx,Wy->KWCU', X, v_xaea, rdm_ca, optimize = einsum_type)
    sigma_KWCU_abab += 1/3 * einsum('KixU,iyCz,Wxyz->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_abab += 1/6 * einsum('KixU,iyCz,Wxzy->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_abab -= 1/2 * einsum('Kixy,ixCy,UW->KWCU', X, v_xaea, rdm_ca, optimize = einsum_type)
    sigma_KWCU_abab += 1/3 * einsum('Kixy,ixCz,UzWy->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_abab += 1/6 * einsum('Kixy,ixCz,UzyW->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_abab += einsum('Kixy,iyCx,UW->KWCU', X, v_xaea, rdm_ca, optimize = einsum_type)
    sigma_KWCU_abab -= 2/3 * einsum('Kixy,iyCz,UzWx->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_abab -= 1/3 * einsum('Kixy,iyCz,UzxW->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_abab += 1/6 * einsum('Kixy,izCw,UwzWxy->KWCU', X, v_xaea, rdm_cccaaa, optimize = einsum_type)
    sigma_KWCU_abab -= 1/6 * einsum('Kixy,izCw,UwzWyx->KWCU', X, v_xaea, rdm_cccaaa, optimize = einsum_type)
    sigma_KWCU_abab -= 1/6 * einsum('Kixy,izCw,UwzxyW->KWCU', X, v_xaea, rdm_cccaaa, optimize = einsum_type)
    sigma_KWCU_abab -= 1/6 * einsum('Kixy,izCw,UwzyWx->KWCU', X, v_xaea, rdm_cccaaa, optimize = einsum_type)
    sigma_KWCU_abab -= 1/6 * einsum('Kixy,izCw,UwzyxW->KWCU', X, v_xaea, rdm_cccaaa, optimize = einsum_type)
    sigma_KWCU_abab -= 1/2 * einsum('Kixy,izCx,UzWy->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_abab += 1/3 * einsum('Kixy,izCy,UzWx->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_abab += 1/6 * einsum('Kixy,izCy,UzxW->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma[caea__abab] += ascontiguousarray(sigma_KWCU_abab).reshape(-1)

    sigma_KWCU_baab =- einsum('KiUx,ixCy,Wy->KWCU', X, v_xaea, rdm_ca, optimize = einsum_type)
    sigma_KWCU_baab += 1/2 * einsum('KiUx,iyCx,Wy->KWCU', X, v_xaea, rdm_ca, optimize = einsum_type)
    sigma_KWCU_baab += 1/2 * einsum('KiUx,iyCz,Wxzy->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_baab += 1/2 * einsum('KixU,ixCy,Wy->KWCU', X, v_xaea, rdm_ca, optimize = einsum_type)
    sigma_KWCU_baab -= 1/6 * einsum('KixU,iyCz,Wxyz->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_baab -= 1/3 * einsum('KixU,iyCz,Wxzy->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
