    sigma_KWCU_baab -= 1/3 * einsum('Kixy,ixCz,UzyW->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_baab += 1/3 * einsum('Kixy,iyCz,UzWx->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_baab += 2/3 * einsum('Kixy,iyCz,UzxW->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_baab -= 1/6 * einsum('Kixy,izCw,UwzWxy->KWCU', X, v_xaea, rdm_cccaaa, optimize = einsum_type)
    sigma_KWCU_baab -= 1/3 * einsum('Kixy,izCw,UwzxWy->KWCU', X, v_xaea, rdm_cccaaa, optimize = einsum_type)
    sigma_KWCU_baab -= 1/6 * einsum('Kixy,izCy,UzWx->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
    sigma_KWCU_baab -= 1/3 * einsum('Kixy,izCy,UzxW->KWCU', X, v_xaea, rdm_ccaa, optimize = einsum_type)
